def hash_passwords(
    usernames: List[str], passwords: List[str]
) -> List[Tuple[bytes, bytes]]:
    return [
        (
            hashlib.pbkdf2_hmac(
                'sha256', password.encode('utf-8'), os.urandom(32), 10000
            ),
            os.urandom(32),
        )
        for password in passwords
    ]

